using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol/1.2.0/lib/net10.0/ModelContextProtocol.dll");

// Get all types
var types = asm.GetTypes();

// Find attribute types
var attribs = types.Where(t => t.Name.Contains("Attribute")).OrderBy(t => t.Name);
Console.WriteLine("=== ATTRIBUTES ===");
foreach (var t in attribs)
{
    Console.WriteLine($"{t.FullName}");
    foreach (var c in t.GetConstructors())
    {
        var pars = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  ctor({pars})");
    }
}

// Find McpServerTool, McpServerPrompt, McpServerResource
Console.WriteLine("\n=== KEY MCP TYPES ===");
var keyTypes = new[] { "McpServerTool", "McpServerPrompt", "McpServerResource", "McpServer" };
foreach (var typeName in keyTypes)
{
    var t = types.FirstOrDefault(x => x.Name == typeName);
    if (t != null)
    {
        Console.WriteLine($"\n{t.FullName}");
        Console.WriteLine($"  BaseType: {t.BaseType?.Name}");

        var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly);
        if (props.Any())
        {
            Console.WriteLine("  Properties:");
            foreach (var p in props)
            {
                Console.WriteLine($"    {p.Name}: {p.PropertyType.Name}");
            }
        }

        var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
        if (methods.Any())
        {
            Console.WriteLine("  Methods:");
            foreach (var m in methods.Take(5))
            {
                var pars = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name}"));
                Console.WriteLine($"    {m.Name}({pars}): {m.ReturnType.Name}");
            }
        }
    }
}

// Show all namespaces
Console.WriteLine("\n=== NAMESPACES ===");
var namespaces = types.Select(t => t.Namespace).Distinct().OrderBy(x => x);
foreach (var ns in namespaces)
{
    Console.WriteLine(ns);
}
EOF
