    public string? Title { get; set; }
    public string? Description { get; set; }

    // JSON serialization
    public JsonSerializerOptions? SerializerOptions { get; set; }
}
```

#### **Dependency Injection Patterns:**

**1. IServiceProvider injection** (DI container):
```csharp
[McpServerTool]
public void MyTool(IServiceProvider services)
{
    var myService = services.GetService<IMyService>();
}
```

**2. CancellationToken** (automatic):
```csharp
[McpServerTool]
public async Task MyTool(CancellationToken cancellationToken)
{
    await Task.Delay(100, cancellationToken);
}
```

**3. McpServer instance** (automatic):
```csharp
[McpServerTool]
public void MyTool(McpServer server)
{
    // Access server capabilities, client info, etc.
    var clientInfo = server.ClientInfo;
}
```

**4. IProgress<ProgressNotificationValue>** (automatic):
```csharp
[McpServerTool]
public async Task MyTool(IProgress<ProgressNotificationValue> progress)
{
    progress.Report(new ProgressNotificationValue { Progress = 25 });
}
```

**5. FromKeyedServices** (attribute-based):
```csharp
[McpServerTool]
public void MyTool(
    [FromKeyedServices("myKey")] IMyService service)
{
    // Resolves keyed service from DI
}
```

**6. Services property on creation** (builder pattern):
```csharp
var options = new McpServerToolCreateOptions
{
    Services = host.Services  // Provide DI container at creation time
};

var tool = McpServerTool.Create(methodInfo, options);
```

---

### **Complete Registration Example:**

```csharp
using ModelContextProtocol.Server;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

[McpServerToolType]
public class Tools
{
    private readonly IHttpClientFactory _httpFactory;

    public Tools(IHttpClientFactory httpFactory) => _httpFactory = httpFactory;

    [McpServerTool(Name = "fetch_url", Title = "Fetch URL Content")]
    public async Task<string> FetchUrl(
        string url,
        CancellationToken cancellationToken,
        IProgress<ProgressNotificationValue> progress)
    {
        progress.Report(new ProgressNotificationValue { Progress = 10 });
        var client = _httpFactory.CreateClient();
        var response = await client.GetAsync(url, cancellationToken);
        return await response.Content.ReadAsStringAsync();
    }
}

[McpServerPromptType]
public class Prompts
{
    [McpServerPrompt(Name = "analyze_code")]
    public PromptMessage[] AnalyzeCode(string code)
    {
        return new[] { /* ... */ };
    }
}

// In Program.cs
var host = Host.CreateDefaultBuilder(args)
    .ConfigureServices((context, services) =>
    {
        services.AddHttpClient();
        services.AddScoped<Tools>();

        services.AddMcpServer()
            .WithStdioServerTransport()
            .WithTools<Tools>()
            .WithPrompts<Prompts>();
    })
    .Build();

await host.RunAsync();
```

---

### **Key Summary:**

| Aspect | Pattern |
|--------|---------|
| **Server Registration** | `services.AddMcpServer().WithStdioServerTransport()` |
| **Tool Definition** | `[McpServerTool]` on methods in `[McpServerToolType]` classes |
| **Prompt Definition** | `[McpServerPrompt]` on methods in `[McpServerPromptType]` classes |
| **Resource Definition** | `[McpServerResource]` on methods/properties in `[McpServerResourceTypeAttribute]` classes |
| **Base Classes** | `McpServerTool`, `McpServerPrompt`, `McpServerResource` (abstract) |
| **DI Support** | `IServiceProvider`, `CancellationToken`, `McpServer`, `IProgress<ProgressNotificationValue>`, `[FromKeyedServices]` |
| **Namespaces** | `ModelContextProtocol.Server`, `Microsoft.Extensions.DependencyInjection` |

