using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools
{
    private readonly IHttpClientFactory _httpClientFactory;
    private readonly ILogger<ApiTools> _logger;

    public ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
    {
        _httpClientFactory = httpClientFactory;
        _logger = logger;
    }

    [McpServerTool(Name = "fetch_api"), Description("Fetches JSON data from an external API endpoint.")]
    public async Task<string> FetchApiAsync(
        [Description("The full URL of the API endpoint to call.")] string url,
        CancellationToken cancellationToken)
    {
        _logger.LogInformation("Calling external API: {Url}", url);

        using var client = _httpClientFactory.CreateClient("ExternalApi");
        using var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        var result = JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });

        _logger.LogInformation("API call succeeded ({StatusCode})", (int)response.StatusCode);
        return result;
    }
}

using System.ComponentModel;
using ModelContextProtocol;
using ModelContextProtocol.Server;

[McpServerPromptType]
public class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum length hint (e.g. '2 sentences').")] string? maxLength = null)
    {
        var constraint = string.IsNullOrWhiteSpace(maxLength)
            ? string.Empty
            : $" Keep the summary within {maxLength}.";

        return
        [
            new()
            {
                Role = Role.User,
                Content = new Content($"Summarize the following text concisely.{constraint}\n\n{text}")
            }
        ];
    }
}

